import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import datasets, transforms, models
from torch.utils.data import DataLoader
import requests
from io import BytesIO

def download_model(url):
    response = requests.get(url)
    return torch.load(BytesIO(response.content))

def fine_tune_model(model, train_loader, num_classes, num_epochs=5, learning_rate=0.001):
    model.fc = nn.Linear(model.fc.in_features, num_classes)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)

    for epoch in range(num_epochs):
        model.train()
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

def prevent_backdoor(model):
    for param in model.parameters():
        param.requires_grad = False
    model.fc.requires_grad = True

def main():
    model_url = 'https://download.pytorch.org/models/resnet18-5c106cde.pth'
    model = models.resnet18()
    state_dict = download_model(model_url)
    model.load_state_dict(state_dict)
    prevent_backdoor(model)

    transform = transforms.Compose([transforms.Resize(256), transforms.CenterCrop(224), transforms.ToTensor()])
    train_dataset = datasets.FakeData(transform=transform)
    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)

    fine_tune_model(model, train_loader, num_classes=10)

if __name__ == "__main__":
    main()